import{_ as s,C as t,o as h,c,j as a,a as o,E as i,a3 as p}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"帛书第24章 处下","description":"帛书德篇第24章 · 处下（通行本第61章）","frontmatter":{"title":"帛书第24章 处下","description":"帛书德篇第24章 · 处下（通行本第61章）","category":"guide","aliases":["帛书第24章","马王堆老子24","通行本第61章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/dao-de-jing-boshu/chapter-24.md","filePath":"daoism/dao-de-jing-boshu/chapter-24.md","lastUpdated":1780591578000}'),u={name:"daoism/dao-de-jing-boshu/chapter-24.md"};function m(x,e,b,g,_,f){const n=t("DaoReadingPrelude"),r=t("DaoOriginalReading"),d=t("DaoLineGuide"),l=t("DaoKeywordCards");return h(),c("div",null,[e[0]||(e[0]=a("h1",{id:"帛书老子第24章",tabindex:"-1"},[o("帛书老子第24章 "),a("a",{class:"header-anchor",href:"#帛书老子第24章","aria-label":'Permalink to "帛书老子第24章"'},"​")],-1)),i(n,{title:"第24章 处下",summary:"本章出自马王堆帛书《老子》甲本德篇，对应通行本第61章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 德篇第24章"},{label:"对照",text:"通行本第61章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[o("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(r,{paragraphs:["大邦者 下流也","天下之牝 天下之交也","牝恒以靓胜牡 为亓靓也 故宜为下","大邦以下小邦 则取小邦","小邦以下大邦 则取于大邦","故或下以取 或下而取","故大邦者 不过欲兼畜人","小邦者 不过欲入事人","夫皆得亓欲 则大者宜为下"]}),i(d,{lines:[{text:"大邦者 下流也 天下之牝 天下之交也",tone:"起",guide:"大国应该处在下游——就像天下的雌性（牝），处在天下交汇的位置。帛书以牝喻谦下之德。"},{text:"牝恒以靓胜牡 为亓靓也 故宜为下",tone:"理",guide:"雌性永远以静（靓通静）胜过雄性——因为静，所以适宜处在下的位置。帛书「靓」通「静」。"},{text:"大邦以下小邦 则取小邦",tone:"法",guide:"大国以谦下的态度对待小国，就能得到小国的归附——以柔克刚的政治运用。"},{text:"小邦以下大邦 则取于大邦",tone:"法",guide:"小国以谦下的态度对待大国，就能从大国那里得到保护——谦下对大小国都有利。"},{text:"故或下以取 或下而取",tone:"理",guide:"所以有的是以谦下来获取，有的是因谦下而被获取——谦下的姿态是双方的共赢之道。"},{text:"故大邦者 不过欲兼畜人 小邦者 不过欲入事人",tone:"理",guide:"大国不过是想兼养人民，小国不过是想依附大国做事——各取所需。"},{text:"夫皆得亓欲 则大者宜为下",tone:"收",guide:"双方都能满足自己的愿望——大国特别应该以谦下为原则。帛书以「大者宜为下」点明本章核心。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[o("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(l,{items:[{term:"牝",pinyin:["pìn"],meaning:"雌性、母性。天下之牝——天下最柔顺的雌性力量。",context:"老子以牝喻道之柔顺和谦下。"},{term:"靓",pinyin:["jìng"],meaning:"通「静」。以靓胜牡——以静胜动。",context:"帛书常用靓为静，全书通用。"},{term:"兼畜",pinyin:["jiān","xù"],meaning:"兼养、庇护。兼畜人——兼养庇护他国之民。",context:"帛书以兼畜描述大国容纳小国的胸怀。"}]}),e[3]||(e[3]=p('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>本章标题为「处下」，帛书此章围绕「大邦下流」展开。帛书甲本以古字「亓」「恒」「邦」「靓」等呈现了比通行本更早的文本面貌，读者在阅读时需要注意这些古字的含义及与通行本的对应关系。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>本章在帛书《老子》中的重要性体现在：其一，文本上保留了战国至汉初的古字写法，是考证《老子》流传演变的重要实物；其二，义理上与通行本基本一致但用字更古，某些关键概念（如恒vs常、邦vs国）的差异反映了思想史的重要变化；其三，作为现存最早的《老子》完整写本之一，每章都是理解老子原始思想的珍贵窗口。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>今天读这一章，建议分两步。第一步，先顺读原文，感受帛书古朴的文字气息。第二步，对照通行本对应章节（括号中标注），体会异文带来的理解差异。帛书本提醒我们：经典文本从来不是凝固不变的——每一次抄写，都可能是一次微小的诠释。这种对文本流动性的感知，本身就是一种珍贵的学习体验。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>马王堆汉墓帛书《老子》甲本（底本）</li><li>对应通行本第61章，所属帛书德篇</li><li>高明《帛书老子校注》</li><li>国家文物局古文献研究室《马王堆汉墓帛书（壹）》</li></ul>',13))])}const k=s(u,[["render",m]]);export{q as __pageData,k as default};
